import json
import logging
import os
import datetime
from typing import Optional

import azure.functions as func
from azure.identity import DefaultAzureCredential, ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient
from azure.core.credentials import AzureKeyCredential
from azure.core.messaging import CloudEvent


# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage_account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos_account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "processing-results")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get("EVENT_GRID_TOPIC_ENDPOINT", "https://<topic>.eventgrid.azure.net/api/events")
SOURCE_CONTAINER_NAME = os.environ.get("SOURCE_CONTAINER_NAME", "input-files")
PROCESSED_CONTAINER_NAME = os.environ.get("PROCESSED_CONTAINER_NAME", "processed-files")
MANAGED_IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID", None)

app = func.FunctionApp()


def get_credential():
    """
    Get Azure credential using Managed Identity.
    
    SECURITY NOTE: This MVP uses broad permissions for rapid development.
    For production, follow the principle of least privilege:
    - Storage: Use Storage Blob Data Reader if only reading, scope to specific containers
    - Cosmos DB: Use Cosmos DB Account Reader if only reading, or use built-in data plane RBAC
    - Event Grid: Scope Event Grid Data Sender to specific topics only
    
    TODO (before production):
    - Narrow role assignments to specific resource scopes
    - Replace Cosmos DB Account Contributor with data-plane RBAC roles
    - Add network restrictions (Private Endpoints, VNet integration)
    - Implement key rotation strategy if using connection strings as fallback
    - Enable diagnostic logging and monitoring
    """
    if MANAGED_IDENTITY_CLIENT_ID:
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
    return DefaultAzureCredential()


def get_blob_service_client() -> BlobServiceClient:
    """Create Blob Service Client using Managed Identity."""
    credential = get_credential()
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def get_cosmos_client() -> CosmosClient:
    """Create Cosmos DB client using Managed Identity."""
    credential = get_credential()
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def get_event_grid_client() -> EventGridPublisherClient:
    """Create Event Grid publisher client using Managed Identity."""
    credential = get_credential()
    return EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)


def ensure_cosmos_resources(cosmos_client: CosmosClient):
    """Ensure Cosmos DB database and container exist."""
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/partitionKey"),
        offer_throughput=400
    )
    return database, container


def process_file_content(blob_name: str, content: bytes) -> dict:
    """
    Process file content and return structured results.
    Replace this with actual business logic.
    """
    content_str = content.decode("utf-8", errors="replace")
    
    result = {
        "fileName": blob_name,
        "fileSize": len(content),
        "lineCount": content_str.count("\n") + 1 if content_str else 0,
        "wordCount": len(content_str.split()) if content_str else 0,
        "charCount": len(content_str),
        "processedAt": datetime.datetime.utcnow().isoformat(),
        "status": "processed",
        "contentPreview": content_str[:500] if content_str else "",
    }
    
    return result


def write_to_cosmos(container, blob_name: str, processing_result: dict) -> dict:
    """Write processing results to Cosmos DB."""
    document = {
        "id": f"{blob_name}-{datetime.datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}",
        "partitionKey": blob_name.split("/")[0] if "/" in blob_name else "default",
        "blobName": blob_name,
        "results": processing_result,
        "createdAt": datetime.datetime.utcnow().isoformat(),
        "ttl": -1,  # No expiration; set to seconds for auto-expiration
    }
    
    created_item = container.upsert_item(body=document)
    logging.info(f"Written document {created_item['id']} to Cosmos DB")
    return created_item


def send_event_grid_notification(
    event_grid_client: EventGridPublisherClient,
    blob_name: str,
    processing_result: dict,
    cosmos_document_id: str,
    event_type: str = "FileProcessing.Completed"
):
    """Send notification via Event Grid."""
    event = CloudEvent(
        source="azure-function/file-processor",
        type=event_type,
        data={
            "blobName": blob_name,
            "status": processing_result.get("status", "unknown"),
            "fileSize": processing_result.get("fileSize", 0),
            "cosmosDocumentId": cosmos_document_id,
            "processedAt": processing_result.get("processedAt", ""),
        },
        subject=f"files/{blob_name}",
    )
    
    event_grid_client.send([event])
    logging.info(f"Event Grid notification sent for {blob_name}")


def move_blob_to_processed(blob_service_client: BlobServiceClient, blob_name: str):
    """Move processed blob to the processed container."""
    source_container = blob_service_client.get_container_client(SOURCE_CONTAINER_NAME)
    dest_container = blob_service_client.get_container_client(PROCESSED_CONTAINER_NAME)
    
    # Ensure destination container exists
    try:
        dest_container.get_container_properties()
    except Exception:
        dest_container.create_container()
    
    source_blob = source_container.get_blob_client(blob_name)
    dest_blob = dest_container.get_blob_client(blob_name)
    
    # Copy blob to processed container
    dest_blob.start_copy_from_url(source_blob.url)
    
    # Delete from source
    source_blob.delete_blob()
    logging.info(f"Moved blob {blob_name} to {PROCESSED_CONTAINER_NAME}")


# ---- Azure Function Triggers ----

@app.blob_trigger(
    arg_name="myblob",
    path=f"{SOURCE_CONTAINER_NAME}/{{name}}",
    connection="AzureWebJobsStorage"
)
def blob_trigger_processor(myblob: func.InputStream):
    """
    Blob-triggered function: automatically processes files when they are
    uploaded to the input container.
    """
    blob_name = myblob.name
    logging.info(f"Blob trigger fired for: {blob_name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        content = myblob.read()
        
        # Process the file
        processing_result = process_file_content(blob_name, content)
        logging.info(f"File processed: {json.dumps(processing_result, default=str)}")
        
        # Write results to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_resources(cosmos_client)
        cosmos_doc = write_to_cosmos(container, blob_name, processing_result)
        
        # Send Event Grid notification
        try:
            event_grid_client = get_event_grid_client()
            send_event_grid_notification(
                event_grid_client,
                blob_name,
                processing_result,
                cosmos_doc["id"],
            )
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed (non-critical): {eg_error}")
        
        # Move blob to processed container
        try:
            blob_service_client = get_blob_service_client()
            # Extract just the file name without the container prefix
            file_name = blob_name.split("/", 1)[-1] if "/" in blob_name else blob_name
            move_blob_to_processed(blob_service_client, file_name)
        except Exception as move_error:
            logging.warning(f"Failed to move blob (non-critical): {move_error}")
        
        logging.info(f"Successfully processed blob: {blob_name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {str(e)}")
        
        # Send failure notification
        try:
            event_grid_client = get_event_grid_client()
            send_event_grid_notification(
                event_grid_client,
                blob_name,
                {"status": "failed", "error": str(e), "processedAt": datetime.datetime.utcnow().isoformat()},
                "",
                event_type="FileProcessing.Failed",
            )
        except Exception as eg_error:
            logging.warning(f"Failed to send error notification: {eg_error}")
        
        raise


@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function: manually trigger processing of a specific blob.
    
    Request body:
    {
        "containerName": "input-files",
        "blobName": "example.txt"
    }
    """
    logging.info("HTTP trigger: manual file processing request")
    
    try:
        req_body = req.get_json()
        container_name = req_body.get("containerName", SOURCE_CONTAINER_NAME)
        blob_name = req_body.get("blobName")
        
        if not blob_name:
            return func.HttpResponse(
                json.dumps({"error": "blobName is required"}),
                status_code=400,
                mimetype="application/json",
            )
        
        # Read blob from storage
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name,
        )
        content = blob_client.download_blob().readall()
        
        # Process the file
        processing_result = process_file_content(blob_name, content)
        
        # Write to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, cosmos_container = ensure_cosmos_resources(cosmos_client)
        cosmos_doc = write_to_cosmos(cosmos_container, blob_name, processing_result)
        
        # Send Event Grid notification
        try:
            event_grid_client = get_event_grid_client()
            send_event_grid_notification(
                event_grid_client,
                blob_name,
                processing_result,
                cosmos_doc["id"],
            )
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed: {eg_error}")
        
        response = {
            "status": "success",
            "blobName": blob_name,
            "cosmosDocumentId": cosmos_doc["id"],
            "processingResult": processing_result,
        }
        
        return func.HttpResponse(
            json.dumps(response, default=str),
            status_code=200,
            mimetype="application/json",
        )
        
    except Exception as e:
        logging.error(f"HTTP trigger error: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=500,
            mimetype="application/json",
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint that verifies connectivity to all services."""
    health = {
        "status": "healthy",
        "timestamp": datetime.datetime.utcnow().isoformat(),
        "services": {},
    }
    
    # Check Blob Storage
    try:
        blob_service_client = get_blob_service_client()
        blob_service_client.get_account_information()
        health["services"]["blobStorage"] = {"status": "connected"}
    except Exception as e:
        health["services"]["blobStorage"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    # Check Cosmos DB
    try:
        cosmos_client = get_cosmos_client()
        list(cosmos_client.list_databases())
        health["services"]["cosmosDb"] = {"status": "connected"}
    except Exception as e:
        health["services"]["cosmosDb"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    # Check Event Grid
    try:
        _ = get_event_grid_client()
        health["services"]["eventGrid"] = {"status": "configured"}
    except Exception as e:
        health["services"]["eventGrid"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    status_code = 200 if health["status"] == "healthy" else 503
    
    return func.HttpResponse(
        json.dumps(health, default=str),
        status_code=status_code,
        mimetype="application/json",
    )


@app.route(route="results", methods=["GET"], auth_level=func.AuthLevel.FUNCTION)
def get_results(req: func.HttpRequest) -> func.HttpResponse:
    """Query processing results from Cosmos DB."""
    try:
        blob_name = req.params.get("blobName")
        limit = int(req.params.get("limit", "10"))
        
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_resources(cosmos_client)
        
        if blob_name:
            query = "SELECT * FROM c WHERE c.blobName = @blobName ORDER BY c.createdAt DESC"
            parameters = [{"name": "@blobName", "value": blob_name}]
        else:
            query = "SELECT * FROM c ORDER BY c.createdAt DESC OFFSET 0 LIMIT @limit"
            parameters = [{"name": "@limit", "value": limit}]
        
        items = list(container.query_items(
            query=query,
            parameters=parameters,
            enable_cross_partition_query=True,
        ))
        
        return func.HttpResponse(
            json.dumps({"count": len(items), "results": items}, default=str),
            status_code=200,
            mimetype="application/json",
        )
        
    except Exception as e:
        logging.error(f"Error querying results: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=500,
            mimetype="application/json",
        )


